	// @ModelAttribute aqui indica que este método será executado
	// antes de qualquer método de request do controller.
	// O que ele retornar ou adicionar no Model ficará disponível
	// para todas as views renderizadas por esse controller.
	@ModelAttribute
	public void getUserDetails(Principal p, Model m) {
	    
	    // 'Principal' representa o usuário autenticado no Spring Security.
	    // Se ninguém estiver logado, o 'p' será null.
	    if (p != null) {
	        // Obtém o nome do usuário logado.
	        // No caso do Spring Security, normalmente é o e-mail ou username.
	        String email = p.getName();
	        
	        // Busca no banco de dados os detalhes completos do usuário
	        // usando o e-mail obtido do Principal.
	        UserDtls userDtls = userService.getUserbyEmail(email);
	        
	        
	        // Adiciona o objeto 'user' ao Model.
	        // Assim, qualquer página renderizada poderá acessar ${user}
	        // e mostrar informações como nome, e-mail, etc.
	        m.addAttribute("user", userDtls);
	        Integer countCart = cartService.getCountCart(userDtls.getId());
	        m.addAttribute("countCart",countCart);
	    }else {
	    	m.addAttribute("user", null);
	    }
	}


	@GetMapping("/")
	public String index(Model m) {
	    // 1) Recupera todos os produtos ativos (lista)
	    // 2) Cria um Stream a partir dessa lista para operar de forma funcional
	    // 3) sorted(...) ordena os elementos do stream. Aqui usamos um Comparator
	    //    que compara os ids de p2 e p1 para obter ordem decrescente por id.
	    //    - p2.getId().compareTo(p1.getId()) retorna:
	    //        > 0 se p2.id > p1.id
	    //        < 0 se p2.id < p1.id
	    //        = 0 se iguais
	    //      Como o resultado é p2.compareTo(p1) (e não p1.compareTo(p2)),
	    //      a ordem final é decrescente (do maior id para o menor).
	    // 4) limit(4) pega apenas os 4 primeiros elementos do stream ordenado
	    // 5) toList() coleta o resultado em uma lista
	    List<Produto> allactiveproduto = produtoService.getAllActiveProducts()
	        .stream()
	        .sorted((p1, p2) -> p2.getId().compareTo(p1.getId())) // ordena por id decrescente
	        .limit(4)                                             // pega os 4 primeiros
	        .toList();                                            // coleta em List

	    // Adiciona a lista ao modelo para ser usada na view "index"
	    m.addAttribute("produto", allactiveproduto);
	    return "index";
	}

