	@GetMapping("/produtos")
	public String produtos(Model m,@RequestParam(name = "pageNo",defaultValue="0") Integer pageNo,
			@RequestParam(name = "pageSize",defaultValue="4") Integer pageSize) {

//		List<Produto> produto = produtoService.getAllActiveProducts();
//		m.addAttribute("produto", produto);
		Page<Produto> page =produtoService.getAllProdutoPagination(pageNo, pageSize);
		m.addAttribute("produto", page.getContent());
		m.addAttribute("pageNo", page.getNumber());
		m.addAttribute("pageSize", pageSize);
		m.addAttribute("totalElements", page.getTotalElements());
		m.addAttribute("totalPages", page.getTotalPages());
		m.addAttribute("isFirst", page.isFirst());
		m.addAttribute("isLast", page.isLast());
		return "produto";
	}

